import React, { useRef } from 'react';
import { View, StyleSheet, Alert, Platform } from 'react-native';
import { WebView } from 'react-native-webview';

const MobileWebsiteViewer = () => {
  const webViewRef = useRef(null);

  // Replace this with the actual URL of your mobile website
  const mobileWebsiteUrl = "https://your-mobile-website.com"; 

  /**
   * Handles messages sent from the WebView using window.ReactNativeWebView.postMessage().
   * The message data is expected to be a JSON string.
   */
  const handleWebViewMessage = (event) => {
    const rawData = event.nativeEvent.data;
    console.log("Received message from WebView:", rawData);

    try {
      const message = JSON.parse(rawData);

      switch (message.type) {
        case 'GET_LOCATION':
          console.log("Web app requested location.");
          // In a real application, you would integrate a native geolocation module here
          // For demonstration, we'll simulate a location and send it back.
          const simulatedLocation = {
            latitude: 34.0522,
            longitude: -118.2437,
            accuracy: 50,
            timestamp: Date.now(),
          };

          Alert.alert(
            "Location Request",
            `Simulating location: Lat ${simulatedLocation.latitude}, Lon ${simulatedLocation.longitude}`
          );

          // Send the location data back to the WebView
          if (webViewRef.current) {
            const jsCode = `
              // In your web app, you would listen for 'message' events on window
              // e.g., window.addEventListener('message', (event) => { ... });
              window.postMessage(${JSON.stringify({ type: 'LOCATION_RESULT', payload: simulatedLocation })}, '*');
              true; // Required to ensure the script executes
            `;
            webViewRef.current.injectJavaScript(jsCode);
          }
          break;

        case 'OPEN_CAMERA':
          console.log("Web app requested camera.");
          // In a real application, you would integrate a native camera module here.
          // e.g., using react-native-image-picker or react-native-camera.
          Alert.alert("Camera Request", "Opening device camera (simulated)");
          // After taking a picture, you might send its URI back to the WebView
          break;

        case 'SHOW_ALERT':
          console.log("Web app requested an alert:", message.payload);
          Alert.alert(message.payload.title || "Message from Web App", message.payload.message || "No message provided.");
          break;

        // Add more cases for other native functionalities your web app might need
        case 'LOG_MESSAGE':
          console.log("Web app debug message:", message.payload);
          break;

        default:
          console.warn("Unknown message type received from WebView:", message.type, message.payload);
          Alert.alert("Unknown Web Message", `Type: ${message.type}\nPayload: ${JSON.stringify(message.payload)}`);
          break;
      }
    } catch (error) {
      console.error("Failed to parse message from WebView:", error);
      Alert.alert("Message Error", "Failed to parse message from web app.");
    }
  };

  return (
    <View style={styles.container}>
      <WebView
        ref={webViewRef}
        source={{ uri: mobileWebsiteUrl }}
        style={styles.webview}
        javaScriptEnabled={true} // Essential to enable JavaScript execution in the WebView
        onMessage={handleWebViewMessage} // This prop enables the message bridge
        // Optional: Add other WebView props as needed
        allowsInlineMediaPlayback={true}
        domStorageEnabled={true}
        startInLoadingState={true}
        // renderLoading={() => <ActivityIndicator size="large" color="#0000ff" />}
        // onError={(syntheticEvent) => {
        //   const { nativeEvent } = syntheticEvent;
        //   console.warn('WebView error: ', nativeEvent);
        // }}
      />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    // Add padding to account for the status bar on iOS
    paddingTop: Platform.OS === 'ios' ? 50 : 0, 
  },
  webview: {
    flex: 1,
  },
});

export default MobileWebsiteViewer;